// TestResourceRefEnumCompleteness verifies that the OpenAPI spec's ResourceRef.resourceType
// enum contains an entry for every resource type that has a wire kind.
func TestResourceRefEnumCompleteness(t *testing.T) {
	specPath := "../../api/openapi/EmergingEnterpriseLandscape-0.1.0-oapi-3.0.3.yaml"
	data, err := os.ReadFile(specPath)
	require.NoError(t, err, "could not read OpenAPI spec")
	spec := string(data)

	wireKinds := []string{
		"ContextType",
		"Context",
		"System",
		"NodeType",
		"FindingType",
		"Node",
		"ApiInstance",
		"API",
		"Component",
		"SystemInstance",
		"ComponentInstance",
		"Finding",
		"OrgUnit",
		"Group",
		"Identity",
	}

	for _, kind := range wireKinds {
		assert.True(t, strings.Contains(spec, "- "+kind),
			"OpenAPI spec ResourceRef.resourceType enum missing entry for %q", kind)
	}
}
